import { wordWrap } from '../utils/zcsvgutils';

export function formatTickWrapByMode(tick, mode, maxWidth, maxHeight, fontHeight) {
    if (tick == null) {
        return tick;
    }
    if (mode == 'wrapOnSpace') {
        return tick.split(' ');
    } else if (mode == 'wrapAll') {
        return wordWrap(tick, maxWidth, maxHeight, fontHeight);
    } else {
        return tick;
    }
}
